#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int subarraySum(vector<int>& nums, int k) {
        int count = 0;
        int cumulative_sum = 0;
        unordered_map<int, int> sum_count = {{0, 1}};
        for (int num : nums) {
            cumulative_sum += num;
            if (sum_count.find(cumulative_sum - k) != sum_count.end()) {
                count += sum_count[cumulative_sum - k];
            }
            sum_count[cumulative_sum]++;
        }
        return count;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.subarraySum(nums, k);
    cout << ans << '\n';
    return 0;
}
